components.css:
.ds-btn-primary {
  background: oklch(0.65 0.2 250);
  color: oklch(0.985 0 0);
  padding: 0.5rem 1rem;
  font-family: Inter, system-ui, -apple-system, sans-serif;
  font-size: 0.875rem;
  font-weight: 500;
  line-height: 1.25;
  border: 1px solid transparent;
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.15s ease, transform 0.15s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  height: 32px;
  white-space: nowrap;
  outline: none;
}
.ds-btn-primary:hover {
  background: oklch(0.58 0.2 250);
}
.ds-btn-primary:focus-visible {
  box-shadow: 0 0 0 3px oklch(0.45 0 0);
}
.ds-btn-primary:active {
  transform: translateY(1px);
}
.ds-btn-primary:disabled {
  opacity: 0.5;
  pointer-events: none;
}

.ds-btn-outline {
  background: oklch(0.145 0 0);
  color: oklch(0.985 0 0);
  padding: 0.5rem 1rem;
  font-family: Inter, system-ui, -apple-system, sans-serif;
  font-size: 0.875rem;
  font-weight: 500;
  line-height: 1.25;
  border: 1px solid oklch(0.22 0 0);
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.15s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  height: 32px;
  white-space: nowrap;
  outline: none;
}
.ds-btn-outline:hover {
  background: oklch(0.22 0 0);
}
.ds-btn-outline:focus-visible {
  box-shadow: 0 0 0 3px oklch(0.45 0 0);
}
.ds-btn-outline:active {
  transform: translateY(1px);
}
.ds-btn-outline:disabled {
  opacity: 0.5;
  pointer-events: none;
}

.ds-card {
  background: oklch(0.155 0 0);
  color: oklch(0.985 0 0);
  border: 1px solid oklch(0.22 0 0);
  border-radius: 8px;
  overflow: hidden;
}
.ds-card-header {
  padding: 1.5rem 1.5rem 0.5rem 1.5rem;
}
.ds-card-title {
  font-family: Inter, system-ui, -apple-system, sans-serif;
  font-size: 0.75rem;
  font-weight: 400;
  line-height: 1.5;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: oklch(0.55 0 0);
  margin: 0;
}
.ds-card-content {
  padding: 0.5rem 1.5rem 1.5rem 1.5rem;
}
.ds-card-metric {
  font-family: Inter, system-ui, -apple-system, sans-serif;
  font-size: 1.875rem;
  font-weight: 700;
  line-height: 1.2;
  color: oklch(0.985 0 0);
  margin: 0;
}

.ds-input {
  background: oklch(0.145 0 0);
  color: oklch(0.985 0 0);
  padding: 0.5rem 0.75rem;
  font-family: Inter, system-ui, -apple-system, sans-serif;
  font-size: 0.875rem;
  line-height: 1.5;
  border: 1px solid oklch(0.22 0 0);
  border-radius: 8px;
  width: 100%;
  outline: none;
  transition: border-color 0.15s ease;
}
.ds-input::placeholder {
  color: oklch(0.55 0 0);
}
.ds-input:focus {
  border-color: oklch(0.65 0.2 250);
}

.ds-badge {
  display: inline-flex;
  align-items: center;
  padding: 0.125rem 0.625rem;
  font-family: Inter, system-ui, -apple-system, sans-serif;
  font-size: 0.75rem;
  font-weight: 500;
  line-height: 1.5;
  color: oklch(0.65 0.2 250);
  background: oklch(0.65 0.2 250 / 0.1);
  border: 1px solid oklch(0.65 0.2 250 / 0.25);
  border-radius: 6px;
  white-space: nowrap;
}

.ds-status-dot {
  display: inline-block;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  flex-shrink: 0;
}
.ds-status-connected {
  background: oklch(0.7 0.18 145);
}
.ds-status-disconnected {
  background: oklch(0.55 0.15 25);
}

.ds-table {
  width: 100%;
  border-collapse: collapse;
  font-family: Inter, system-ui, -apple-system, sans-serif;
  font-size: 0.875rem;
  line-height: 1.5;
  color: oklch(0.985 0 0);
}
.ds-table-header-row {
  background: oklch(0.22 0 0);
}
.ds-table-head {
  padding: 0.75rem 1rem;
  font-size: 0.75rem;
  font-weight: 400;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: oklch(0.55 0 0);
  text-align: left;
}
.ds-table-head-right {
  text-align: right;
}
.ds-table-row {
  border-bottom: 1px solid oklch(0.22 0 0);
  transition: background 0.1s ease;
}
.ds-table-row:hover {
  background: oklch(0.22 0 0 / 0.5);
}
.ds-table-cell {
  padding: 0.75rem 1rem;
  font-size: 0.875rem;
}
.ds-table-cell-right {
  text-align: right;
  font-variant-numeric: tabular-nums;
}
